import java.util.Scanner;

public class MortgageCalculator {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        while (true) {
            try {
                System.out.print("Enter principal loan amount (enter 'exit' to quit): ");
                String principalInput = scanner.nextLine();
                if (principalInput.equalsIgnoreCase("exit")) break;
                double principal = Double.parseDouble(principalInput);

                System.out.print("Enter annual interest rate (as a percentage): ");
                double annualInterestRate = Double.parseDouble(scanner.nextLine());

                System.out.print("Enter loan period in years: ");
                int years = Integer.parseInt(scanner.nextLine());

                if (principal < 0 || annualInterestRate < 0 || years <= 0) {
                    System.out.println("Please enter positive values.");
                    continue;
                }

                double monthlyPayment = calculateMortgage(principal, annualInterestRate, years);
                System.out.printf("Monthly payment: %.2f\n", monthlyPayment);

            } catch (NumberFormatException e) {
                System.out.println("Invalid input. Please enter valid numbers.");
            }
        }

        scanner.close();
    }

    public static double calculateMortgage(double principal, double annualInterestRate, int years) {
        double monthlyInterestRate = (annualInterestRate / 100) / 12;
        int numberOfPayments = years * 12;
        return principal * (monthlyInterestRate * Math.pow(1 + monthlyInterestRate, numberOfPayments)) /
               (Math.pow(1 + monthlyInterestRate, numberOfPayments) - 1);
    }
}

fn paginate_results(page_number: i32, page_size: i32) -> Result<Vec<String>, String> {
    let data = vec![
        String::from("item1"),
        String::from("item2"),
        String::from("item3"),
        String::from("item4"),
        String::from("item5"),
        String::from("item6"),
        String::from("item7"),
        String::from("item8"),
        String::from("item9"),
        String::from("item10"),
    ];

    if page_number <= 0 {
        return Err(String::from("Error: page_number must be greater than 0"));
    }

    if page_size <= 0 {
        return Err(String::from("Error: page_size must be greater than 0"));
    }

    let start_index = (page_number - 1) as usize * page_size as usize;
    let end_index = start_index + page_size as usize;

    if start_index >= data.len() {
        return Err(String::from("Error: page_number is out of range"));
    }

    let subset = data[start_index..end_index.min(data.len())].to_vec();
    Ok(subset)
}

