void saveFilesToDirectory(const std::vector<std::string>& filenames, const std::string& directoryPath) {
    namespace fs = std::filesystem;

    // Check if the directory exists and is writable
    if (!fs::exists(directoryPath) || !fs::is_directory(directoryPath)) {
        std::cerr << "Error: The provided directory does not exist or is not a valid directory.\n";
        return;
    }
    if (!(fs::status(directoryPath).permissions() & fs::perms::owner_write)) {
        std::cerr << "Error: The provided directory is not writable.\n";
        return;
    }

    for (const auto& filename : filenames) {
        try {
            fs::path sourcePath(filename);
            fs::path destinationPath = fs::path(directoryPath) / sourcePath.filename();

            if (!fs::exists(sourcePath)) {
                std::cerr << "Error: File \"" << filename << "\" does not exist.\n";
                continue;
            }

            // Move the file
            fs::rename(sourcePath, destinationPath);
            std::cout << "Success: Moved \"" << filename << "\" to \"" << directoryPath << "\".\n";
        } catch (const fs::filesystem_error& e) {
            std::cerr << "Error: Failed to move \"" << filename << "\". " << e.what() << "\n";
        }
    }
}

