import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import java.io.File;

class Configuration {
    private int port;
    private int timeout;

    public Configuration(int port, int timeout) {
        this.port = port;
        this.timeout = timeout;
    }

    public int getPort() {
        return port;
    }

    public int getTimeout() {
        return timeout;
    }

    @Override
    public String toString() {
        return "Configuration{port=" + port + ", timeout=" + timeout + "}";
    }
}

public class ConfigurationLoader {
    public static Configuration loadConfiguration(String filePath) throws Exception {
        try {
            File xmlFile = new File(filePath);
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(xmlFile);
            document.getDocumentElement().normalize();

            Element root = document.getDocumentElement();
            NodeList portNodeList = root.getElementsByTagName("port");
            NodeList timeoutNodeList = root.getElementsByTagName("timeout");

            if (portNodeList.getLength() == 0 || timeoutNodeList.getLength() == 0) {
                throw new IllegalArgumentException("Missing required configuration tags: 'port' or 'timeout'.");
            }

            int port;
            int timeout;

            try {
                port = Integer.parseInt(portNodeList.item(0).getTextContent());
            } catch (NumberFormatException e) {
                throw new IllegalArgumentException("Invalid format for 'port'. Must be an integer.", e);
            }

            try {
                timeout = Integer.parseInt(timeoutNodeList.item(0).getTextContent());
            } catch (NumberFormatException e) {
                throw new IllegalArgumentException("Invalid format for 'timeout'. Must be an integer.", e);
            }

            return new Configuration(port, timeout);
        } catch (FileNotFoundException e) {
            throw new FileNotFoundException("The specified file was not found: " + filePath);
        } catch (IOException e) {
            throw new IOException("Error reading the file: " + filePath, e);
        } catch (Exception e) {
            throw new Exception("An error occurred while loading the configuration.", e);
        }
    }
}

