use std::any::Any;

fn filter_above_threshold(values: Vec<Box<dyn Any>>, threshold: i64) -> Vec<i64> {
    let mut result = Vec::new();

    for value in values {
        if let Some(num) = value.downcast_ref::<i64>() {
            if *num <= threshold {
                result.push(*num);
            }
        } else if let Some(num) = value.downcast_ref::<f64>() {
            if *num <= threshold as f64 {
                result.push(*num as i64);
            }
        }
        // Non-numeric or nil values are ignored
    }

    result
}

fn main() {
    let values: Vec<Box<dyn Any>> = vec![
        Box::new(10),
        Box::new(20.5),
        Box::new(30),
        Box::new("string"), // Non-numeric value
        Box::new(15.0),
        Box::new(5),
    ];
    let threshold = 15;

    let filtered_values = filter_above_threshold(values, threshold);
    println!("{:?}", filtered_values);
}

