void configureFeatures(std::set<std::string>& enabledFeatures, json& configOptions) {
    const std::set<std::string> defaultEnabledFeatures = enabledFeatures;
    const json defaultConfigOptions = configOptions;

    while (true) {
        std::cout << "Menu:\n";
        std::cout << "1. Enable Feature\n";
        std::cout << "2. Disable Feature\n";
        std::cout << "3. Update Feature Parameters\n";
        std::cout << "4. View Current Configuration\n";
        std::cout << "5. Save Configuration to File\n";
        std::cout << "6. Load Configuration from File\n";
        std::cout << "7. Revert to Default Settings\n";
        std::cout << "8. Exit\n";
        std::cout << "Choose an option: ";

        int choice;
        std::cin >> choice;

        if (choice == 8) break;

        switch (choice) {
            case 1: {
                std::cout << "Enter feature name to enable: ";
                std::string feature;
                std::cin >> feature;
                if (configOptions.contains(feature)) {
                    enabledFeatures.insert(feature);
                    std::cout << "Feature enabled.\n";
                } else {
                    std::cout << "Invalid feature name.\n";
                }
                break;
            }
            case 2: {
                std::cout << "Enter feature name to disable: ";
                std::string feature;
                std::cin >> feature;
                if (enabledFeatures.erase(feature)) {
                    std::cout << "Feature disabled.\n";
                } else {
                    std::cout << "Invalid feature name.\n";
                }
                break;
            }
            case 3: {
                std::cout << "Enter feature name to update: ";
                std::string feature;
                std::cin >> feature;
                if (configOptions.contains(feature)) {
                    std::cout << "Enter JSON configuration (key:value pairs) for " << feature << ": ";
                    std::string input;
                    std::cin.ignore();
                    std::getline(std::cin, input);
                    try {
                        json newConfig = json::parse(input);
                        configOptions[feature] = newConfig;
                        std::cout << "Feature parameters updated.\n";
                    } catch (const json::parse_error&) {
                        std::cout << "Invalid configuration format.\n";
                    }
                } else {
                    std::cout << "Invalid feature name.\n";
                }
                break;
            }
            case 4: {
                std::cout << "Enabled Features:\n";
                for (const std::string& feature : enabledFeatures) {
                    std::cout << "- " << feature << "\n";
                }
                std::cout << "Configuration Options:\n" << configOptions.dump(4) << "\n";
                break;
            }
            case 5: {
                std::cout << "Enter filename to save configuration: ";
                std::string filename;
                std::cin >> filename;
                std::ofstream configFile(filename);
                if (configFile.is_open()) {
                    json saveData = {{"enabledFeatures", enabledFeatures}, {"configOptions", configOptions}};
                    configFile << saveData.dump(4);
                    configFile.close();
                    std::cout << "Configuration saved.\n";
                } else {
                    std::cout << "Failed to save configuration.\n";
                }
                break;
            }
            case 6: {
                std::cout << "Enter filename to load configuration: ";
                std::string filename;
                std::cin >> filename;
                std::ifstream configFile(filename);
                if (configFile.is_open()) {
                    json loadData;
                    try {
                        configFile >> loadData;
                        enabledFeatures = loadData.at("enabledFeatures").get<std::set<std::string>>();
                        configOptions = loadData.at("configOptions");
                        std::cout << "Configuration loaded.\n";
                    } catch (const json::exception&) {
                        std::cout << "Invalid configuration format in file.\n";
                    }
                    configFile.close();
                } else {
                    std::cout << "Failed to load configuration.\n";
                }
                break;
            }
            case 7: {
                enabledFeatures = defaultEnabledFeatures;
                configOptions = defaultConfigOptions;
                std::cout << "Reverted to default settings.\n";
                break;
            }
            default: {
                std::cout << "Invalid option. Try again.\n";
                break;
            }
        }
    }
}

