public class ScreenBrightness {

    public static void adjustBrightness(float currentBrightness) {
        if (currentBrightness < 0.0f || currentBrightness > 1.0f) {
            System.out.println("Error: Invalid brightness level. Must be between 0.0 and 1.0.");
            return;
        }

        Scanner scanner = new Scanner(System.in);
        System.out.println("Current brightness level: " + currentBrightness);
        System.out.println("Enter 'increase', 'decrease', or 'reset' to adjust brightness:");
        String userInput = scanner.nextLine().trim().toLowerCase();

        switch (userInput) {
            case "increase":
                currentBrightness += 0.1f;
                if (currentBrightness > 1.0f) {
                    currentBrightness = 1.0f;
                    System.out.println("Brightness is already at maximum.");
                } else {
                    System.out.println("Brightness increased to: " + currentBrightness);
                }
                break;

            case "decrease":
                currentBrightness -= 0.1f;
                if (currentBrightness < 0.0f) {
                    currentBrightness = 0.0f;
                    System.out.println("Brightness is already at minimum.");
                } else {
                    System.out.println("Brightness decreased to: " + currentBrightness);
                }
                break;

            case "reset":
                currentBrightness = 0.5f;
                System.out.println("Brightness reset to: " + currentBrightness);
                break;

            default:
                System.out.println("Error: Invalid input. Please enter 'increase', 'decrease', or 'reset'.");
        }
    }

    public static void main(String[] args) {
        adjustBrightness(0.5f);
    }
}

