import java.util.Set;

public class UniqueElementAnalyzer {

    public static class EmptySetException extends Exception {
        public EmptySetException(String message) {
            super(message);
        }
    }

    /**
     * Analyzes a set of integers to compute the maximum, minimum, and arithmetic mean.
     *
     * @param numbers Set of integers to analyze.
     * @return A Result object containing maximum, minimum, and mean values.
     * @throws EmptySetException if the input set is empty.
     */
    public static Result uniqueElementAnalyzer(Set<Integer> numbers) throws EmptySetException {
        if (numbers == null || numbers.isEmpty()) {
            throw new EmptySetException("The input set is empty. Cannot perform analysis.");
        }

        int max = Integer.MIN_VALUE;
        int min = Integer.MAX_VALUE;
        int sum = 0;

        for (int num : numbers) {
            if (num > max) max = num;
            if (num < min) min = num;
            sum += num;
        }

        double mean = sum / (double) numbers.size();
        return new Result(max, min, mean);
    }

    /**
     * Represents the result of set analysis, including maximum, minimum, and mean values.
     */
    public static class Result {
        private final int max;
