std::map<std::string, double> processData(const std::map<std::string, double>& data) {
    std::map<std::string, double> result;

    if (data.empty()) {
        return result; // Return empty result map
    }

    double sum = 0.0;
    double min = std::numeric_limits<double>::max();
    double max = std::numeric_limits<double>::lowest();
    int count = 0;

    for (const auto& pair : data) {
        if (pair.second < 0) {
            return {}; // Return empty map if a negative value is found
        }
        sum += pair.second;
        min = std::min(min, pair.second);
        max = std::max(max, pair.second);
        ++count;
    }

    result["sum"] = sum;
    result["min"] = min;
    result["max"] = max;
    result["average"] = count > 0 ? sum / count : 0.0;

    return result;
}

