std::vector<int> computeShortestPathFromNode(const std::vector<std::vector<int>>& adjacencyMatrix, int startNode) {
    const int INF = std::numeric_limits<int>::max();
    int n = adjacencyMatrix.size();

    if (startNode < 0 || startNode >= n) {
        throw std::invalid_argument("Invalid start node index");
    }

    std::vector<int> distances(n, INF);
    std::vector<bool> visited(n, false);
    distances[startNode] = 0;

    for (int i = 0; i < n; ++i) {
        int minDistance = INF, currentNode = -1;
        for (int j = 0; j < n; ++j) {
            if (!visited[j] && distances[j] < minDistance) {
                minDistance = distances[j];
                currentNode = j;
            }
        }

        if (currentNode == -1) {
            break;
        }

        visited[currentNode] = true;

        for (int k = 0; k < n; ++k) {
            if (adjacencyMatrix[currentNode][k] != 0 && !visited[k]) {
                int newDistance = distances[currentNode] + adjacencyMatrix[currentNode][k];
                if (newDistance < distances[k]) {
                    distances[k] = newDistance;
                }
            }
        }
    }

    return distances;
}

