```python
def process_file_content(file_path: str, binary_mode: bool):
    try:
        mode = 'rb' if binary_mode else 'r'
        with open(file_path, mode) as file:
            content = file.read()
            if binary_mode:
                transformed_content = bytes([min(byte * 2, 255) for byte in content])
            else:
                transformed_content = content.upper()
        return transformed_content
    except (FileNotFoundError, PermissionError) as e:
        return str(e)
