use std::collections::HashMap;

#[derive(Debug)]
struct UserData {
    age: Option<u32>,
    occupation: Option<String>,
    city: Option<String>,
}

fn aggregateUserData(user_map: HashMap<String, UserData>) {
    if user_map.is_empty() {
        eprintln!("Error: User map is empty.");
        return;
    }

    let mut total_age = 0;
    let mut age_count = 0;
    let mut occupation_count: HashMap<String, usize> = HashMap::new();
    let mut city_count: HashMap<String, usize> = HashMap::new();

    for (user_id, user_data) in &user_map {
        if let Some(age) = user_data.age {
            total_age += age;
            age_count += 1;
        }

        if let Some(occupation) = &user_data.occupation {
            *occupation_count.entry(occupation.clone()).or_insert(0) += 1;
        }

        if let Some(city) = &user_data.city {
            *city_count.entry(city.clone()).or_insert(0) += 1;
        }
    }

    if age_count == 0 {
        eprintln!("Error: No valid age data found.");
        return;
    }

    let average_age = total_age as f64 / age_count as f64;

    let most_frequent_occupation = occupation_count.iter()
        .max_by_key(|(_, &count)| count)
        .map(|(occupation, _)| occupation.clone())
        .unwrap_or_else(|| {
            eprintln!("Error: No valid occupation data found.");
            "Unknown".to_string()
        });

    let most_common_city = city_count.iter()
        .max_by_key(|(_, &count)| count)
        .map(|(city, _)| city.clone())
        .unwrap_or_else(|| {
            eprintln!("Error: No valid city data found.");
            "Unknown".to_string()
        });

    println!("Average Age: {:.2}", average_age);
    println!("Most Frequent Occupation: {}", most_frequent_occupation);
    println!("Most Common City: {}", most_common_city);
}

fn main() {
    let mut user_map = HashMap::new();
    user_map.insert(
        "1".to_string(),
        UserData {
            age: Some(25),
            occupation: Some("Engineer".to_string()),
            city: Some("New York".to_string()),
        },
    );
    user_map.insert(
        "2".to_string(),
        UserData {
            age: Some(30),
            occupation: Some("Designer".to_string()),
            city: Some("San Francisco".to_string()),
        },
    );
    aggregateUserData(user_map);
}

