import shutil
import os

def batch_file_transfer(filenames, directory_path):
    if not isinstance(filenames, list) or not all(isinstance(filename, str) for filename in filenames):
        print(f"Error: 'filenames' must be a list of strings.")
        return

    if not isinstance(directory_path, str):
        print(f"Error: 'directory_path' must be a string.")
        return

    if not os.path.isdir(directory_path):
        print(f"Error: Directory '{directory_path}' is inaccessible or does not exist.")
        return

    for filename in filenames:
        try:
            if not os.path.isfile(filename):
                print(f"Error: File '{filename}' does not exist.")
                continue

            shutil.copy(filename, directory_path)
            print(f"Success: File '{filename}' has been copied to '{directory_path}'.")
        except Exception as e:
            print(f"Error: Failed to copy '{filename}' to '{directory_path}'. Reason: {e}")
