import java.util.regex.Pattern;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ContactSubscriptionManager {
    private static final Logger logger = Logger.getLogger(ContactSubscriptionManager.class.getName());
    private static final Pattern EMAIL_PATTERN = Pattern.compile("^[\\w-\\.]+@([\\w-]+\\.)+[\\w-]{2,4}$");

    public static void initializeContactSubscription(String email, boolean subscriptionStatus) {
        try {
            logger.log(Level.INFO, "Starting subscription initialization for email: {0}", email);

            if (email == null || !EMAIL_PATTERN.matcher(email).matches()) {
                logger.log(Level.WARNING, "Invalid email format: {0}", email);
                System.out.println("Error: Invalid email format.");
                return;
            }

            // Simulate updating subscription status
            logger.log(Level.INFO, "Updating subscription status for email: {0}", email);
            System.out.printf("Subscription for %s successfully updated to: %s%n",
                    email, subscriptionStatus ? "Subscribed" : "Unsubscribed");
        } catch (Exception e) {
            logger.log(Level.SEVERE, "An error occurred while updating subscription status.", e);
            System.out.println("Error: Unable to update subscription status.");
        } finally {
            logger.log(Level.INFO, "Subscription initialization operation completed for email: {0}", email);
        }
    }
}
